            '0x1234567890123456789012345678901234567890',
            '0xabcdef1234567890abcdef1234567890abcdef12',
            100.0,
            'your_private_key_here'
        );
        console.log('Transfer successful:', result);
    } catch (error) {
        console.log('Transfer failed:', error.message);
    }
})();
